     * @return the escaped string safe for bash single-quoted usage
     */
    private static String escapeForBash(String s) {
        if (s == null) {
            return "''";
        }
        // Escape single quotes by replacing with '\''
        String escaped = s.replace("'", "'\\''");
        // Wrap the entire escaped string in single quotes
        return "'" + escaped + "'";
    }

    /**
     * Finds files matching the specified pattern in the given directory using the bash find command.
     * Limits results to 10 files, searches only regular files, and handles errors appropriately.
     *
     * @param searchDir   the directory path to search (user input)
     * @param filePattern the file name pattern (supports wildcards like *.txt, user input)
     * @return list of found files (one per line) if successful; error message if search fails
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        // Escape user inputs to prevent command injection vulnerabilities
        String escapedSearchDir = escapeForBash(searchDir);
        String escapedFilePattern = escapeForBash(filePattern);

        // Build the bash command:
        // - set -o pipefail: ensures pipeline exit code reflects failures in find (not just head)
        // - find: searches for regular files (-type f) with matching name (-name)
        // - head -n 10: limits results to maximum 10 files
        String command = String.format(
                "set -o pipefail; find %s -type f -name %s | head -n 10",
                escapedSearchDir,
                escapedFilePattern
        );

        Process process = null;
        try {
            // Configure ProcessBuilder to execute the command via bash -c
            ProcessBuilder processBuilder = new ProcessBuilder("bash", "-c", command);
            // Merge stderr into stdout to capture both normal output and error messages in one stream
            processBuilder.redirectErrorStream(true);
            // Start the process
            process = processBuilder.start();

            // Read the combined output (stdout + stderr) line by line
            List<String> outputLines = new ArrayList<>();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    outputLines.add(line);
                }
            }

            // Wait for the process to complete and retrieve its exit code
            int exitCode = process.waitFor();

            if (exitCode == 0) {
                // Success: join the output lines with system-specific line separator
                return String.join(System.lineSeparator(), outputLines);
            } else {
                // Failure: return the collected error output
                return String.join(System.lineSeparator(), outputLines);
            }

        } catch (IOException e) {
            // Handle IO exceptions (e.g., failure to start bash, read/write errors)
            return "IOException occurred: " + e.getMessage();
        } catch (InterruptedException e) {
            // Restore interrupt status and handle thread interruption
            Thread.currentThread().interrupt();
            return "Search was interrupted: " + e.getMessage();
        } finally {
            // Ensure the process is destroyed to release system resources
            if (process != null) {
                process.destroy();
            }
        }
    }
}
